#include<bits/stdc++.h>
using namespace std;

long long n,a[1000001],maxx,ant,lest,mid;

int main() {
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	sort(a+1,a+1+n);
	mid=n/2;
	for(int i=1;i<=n;i++){
		if(a[i]==lest){
			ant++;
		}else{
			if(ant>mid){
				cout<<lest;
				return 0;
			}else{
				ant=1;
                lest=a[i];
			}
		}
	}
	cout<<"No";
	return 0;
}
